// BAD — one fat interface
abstract class Printer {
  void print(Doc d);
  void scan(Doc d);
  void fax(Doc d);
}

class SimplePrinter implements Printer {
  @override void print(Doc d) { ... }
  @override void scan(Doc d) { throw 'not supported'; }   // 😬
  @override void fax(Doc d)  { throw 'not supported'; }   // 😬
}

// GOOD — small focused interfaces
abstract class Printable { void print(Doc d); }
abstract class Scannable { void scan(Doc d);  }
abstract class Faxable   { void fax(Doc d);   }

class SimplePrinter implements Printable { @override void print(Doc d) {...} }
class Xerox implements Printable, Scannable, Faxable { ... }

// BAD — high-level OrderService directly depends on a concrete DB class.
class OrderService {
  final SqlOrderRepo repo = SqlOrderRepo();   // ← hard-coded!
  void place(Order o) => repo.save(o);
}
// Now testing is a nightmare — you can't swap in a fake DB.
// Migrating from SQL to Firestore means touching every service.

// GOOD — depend on an abstraction, INJECT the concrete implementation.
abstract class OrderRepo { void save(Order o); }
class SqlOrderRepo   implements OrderRepo { @override void save(Order o) {...} }
class FakeOrderRepo  implements OrderRepo { @override void save(Order o) {} }

class OrderService {
  final OrderRepo repo;               // depends on ABSTRACTION
  OrderService(this.repo);            // constructor injection
  void place(Order o) => repo.save(o);
}

// Wire it up:
final service = OrderService(SqlOrderRepo());     // in production
final test    = OrderService(FakeOrderRepo());    // in tests

// File: solid_demo.dart — the BEFORE version
class NotificationService {
  void notify(User u, String msg, String channel) {
    // Validation
    if (u.email.isEmpty && u.phone.isEmpty) throw 'invalid user';
    // Choose channel
    if (channel == 'email') {
      final smtp = SmtpClient('smtp.mail.com', 587);   // hardcoded
      smtp.send(u.email, msg);
    } else if (channel == 'sms') {
      final gw = TwilioGateway('acct-xyz');            // hardcoded
      gw.send(u.phone, msg);
    }
    // Log
    print('Sent $channel to ${u.name} at ${DateTime.now()}');
  }
}

// Problems:
// SRP — validates, chooses, sends, logs — 4 reasons to change.
// OCP — adding WhatsApp = editing this method.
// DIP — hard-codes SmtpClient and TwilioGateway.
// Testing — impossible without hitting real SMTP/Twilio.

// File: solid_demo.dart — the AFTER version

// Abstraction (I + D): tiny, focused interface
abstract class Channel { void send(User u, String msg); }

// Each concrete channel = one focused class (S)
class EmailChannel extends Channel {
  final SmtpClient _smtp;
  EmailChannel(this._smtp);
  @override void send(User u, String msg) => _smtp.send(u.email, msg);
}

class SmsChannel extends Channel {
  final SmsGateway _gw;
  SmsChannel(this._gw);
  @override void send(User u, String msg) => _gw.send(u.phone, msg);
}

// New channel? Just add a class — NO edit to NotificationService (O)
class WhatsAppChannel extends Channel {
  final WhatsAppApi _wa;
  WhatsAppChannel(this._wa);
  @override void send(User u, String msg) => _wa.send(u.phone, msg);
}

// Validation is a separate concern (S)
class UserValidator {
  bool isValid(User u) => u.email.isNotEmpty || u.phone.isNotEmpty;
}

// Now the service only orchestrates — no low-level details (D)
class NotificationService {
  final UserValidator _validator;
  final Channel _channel;                  // depends on abstraction
  final Logger _log;
  NotificationService(this._validator, this._channel, this._log);

  void notify(User u, String msg) {
    if (!_validator.isValid(u)) throw 'invalid user';
    _channel.send(u, msg);
    _log.info('sent to ${u.name}');
  }
}

// Wire it up (dependency injection):
final svc = NotificationService(
  UserValidator(),
  EmailChannel(SmtpClient('smtp.mail.com', 587)),  // pick your channel
  ConsoleLogger(),
);

// In a test, swap in fakes trivially:
final testSvc = NotificationService(
  UserValidator(),
  FakeChannel(),
  FakeLogger(),
);
